args.sparql:
SELECT ?country ?countryLabel (SUM(xsd:integer(?annualOutput)) AS ?totalOutput)
WHERE {
  ?plant wdt:P618 wd:Q12739;
         wdt:P4131 ?annualOutput;
         wdt:P276 ?country.
  ?country rdfs:label ?countryLabel.
  FILTER(LANG(?countryLabel) = 'en')
}
GROUP BY ?country ?countryLabel
ORDER BY DESC(?totalOutput)
LIMIT 5

